gelu_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <c10/cuda/CUDAGuard.h>
#include <math.h>
#include <cmath>
#include <cfloat>

namespace {
constexpr float GELU_COEF = 0.044715f;
constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;  // sqrt(2/π)

// Validate critical constants at compile time (would fail compilation if wrong)
static_assert(fabsf(GELU_COEF - 0.044715f) < 1e-6f, "GELU_COEF constant corrupted");
static_assert(fabsf(SQRT_2_OVER_PI - 0.7978845608028654f) < 1e-6f, "SQRT_2_OVER_PI constant corrupted");

// Use CUDA's built-in tanhf for maximum accuracy and robustness
// This eliminates dependency on custom polynomial approximations
__device__ float robust_tanh(float x) {
    return tanhf(x);
}

// Safe version for half precision - convert to float, use accurate tanhf
__device__ half robust_tanh(half x) {
    return __float2half(tanhf(__half2float(x)));
}
}

template<typename T>
__global__ void gelu_kernel(const T* __restrict__ input, T* __restrict__ output, int size, bool enable_validation) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < size) {
        T x = input[idx];

        // Check for invalid inputs
        if (isnan(__half2float(x)) || isinf(__half2float(x))) {
            output[idx] = T(0.0f);
            return;
        }

        // Convert to float for precise computation regardless of T
        float xf = __half2float(x);
        float x_cubed = xf * xf * xf;
        float inner = SQRT_2_OVER_PI * (xf + GELU_COEF * x_cubed);

        // Use robust tanh implementation
        float tanh_val = tanhf(inner);  // Always use float precision for accuracy

        // Final GELU computation
        float result = 0.5f * xf * (1.0f + tanh_val);

        // Optional runtime validation for debugging/robustness
        if (enable_validation && idx == 0) {
            // Compare with reference implementation for first element
            float reference_inner = 0.7978845608028654f * (xf + 0.044715f * x_cubed);
            float reference_tanh = tanhf(reference_inner);
            float reference_result = 0.5f * xf * (1.0f + reference_tanh);

            // If constants were corrupted, this would detect large errors
            if (fabsf(inner - reference_inner) > 1e-4f || 
                fabsf(result - reference_result) > 1e-4f) {
                // Output NaN to signal validation failure
                output[idx] = __float2half(NAN);
                return;
            }
        }

        output[idx] = __float2half(result);
    }
}

// Specialization for float - same logic but without half conversions
template<>
__global__ void gelu_kernel<float>(const float* __restrict__ input, float* __restrict__ output, int size, bool enable_validation) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < size) {
        float x = input[idx];

        // Check for invalid inputs
        if (isnan(x) || isinf(x)) {
            output[idx] = 0.0f;
            return;
        }

        float x_cubed = x * x * x;
        float inner = SQRT_2_OVER_PI * (x + GELU_COEF * x_cubed);

        // Use CUDA's built-in tanhf for accuracy
        float tanh_val = tanhf(inner);

        float result = 0.5f * x * (1.0f + tanh_val);

        // Optional runtime validation
        if (enable_validation && idx == 0) {
            float reference_inner = 0.7978845608028654f * (x + 0.044715f * x_cubed);
            float reference_tanh = tanhf(reference_inner);
            float reference_result = 0.5f * x * (1.0f + reference_tanh);

            if (fabsf(inner - reference_inner) > 1e-4f || 
                fabsf(result - reference_result) > 1e-4f) {
                output[idx] = NAN;
                return;
            }
        }

        output[idx] = result;
    }
}

torch::Tensor gelu_cuda(torch::Tensor input, bool validate_constants) {
    at::cuda::CUDAGuard guard(input.device());
    auto size = input.numel();
    auto output = torch::empty_like(input);

    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "gelu_cuda", [&] {
        gelu_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            size,
            validate_constants
        );
    });

    // Synchronize and check for validation errors
    cudaDeviceSynchronize();
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error in gelu_kernel: ") + cudaGetErrorString(err));
    }

    // If validation was enabled and detected corruption, raise an error
    if (validate_constants && size > 0) {
        auto first_elem = output[0].item<float>();
        if (std::isnan(first_elem)) {
            throw std::runtime_error("GELU kernel validation failed: Constants may be corrupted");
        }
    }

    return output;
}
